// Deduplicate: if duplicate IDs exist, keep the last (most complete) version
const seenIds = new Set<string>();
export const historicalEvents: HistoricalEvent[] = [];
for (let i = _events.length - 1; i >= 0; i--) {
  if (!seenIds.has(_events[i].id)) {
    seenIds.add(_events[i].id);
    historicalEvents.unshift(_events[i]);
  }
}

if (import.meta.env.DEV && historicalEvents.length !== _events.length) {
  console.warn(`[events] ${_events.length - historicalEvents.length} duplicate event IDs detected and removed`);
}
